"""kaya wire vocabulary. Generated by kaya-bindgen from kaya::spec — do not edit.

Records are {u32 size, u16 kind, u16 flags}, body, padded to 8, little-endian.
Values are {u32 type, u32 len, payload padded to 8}; paths are
{u32 count, u32 reserved, count values}. Keys and values here accept
Python bool, int, float, and str, mapped to the kaya value types.
"""

import struct

# SPEC_HASH: the protocol fingerprint; the runtime asserts the loaded core agrees.
SPEC_HASH = 0xe43514ac23c5f1c5

VALUE_BOOL = 1
VALUE_I64 = 2
VALUE_F64 = 3
VALUE_STR = 4
KIND_COLUMN = 1
KIND_BUTTON = 2
KIND_LABEL = 3
KIND_ENTRY = 4
KIND_ROW = 5
KIND_CHECKBOX = 6
PROP_TEXT = 1
PROP_CHECKED = 2
SOURCE_CONST = 0
SOURCE_SIGNAL = 1
SOURCE_ELEMENT = 2
OCCURRENCE_PAD = 0
OCCURRENCE_BUTTON_CLICKED = 1
OCCURRENCE_TEXT_CHANGED = 2
OCCURRENCE_TOGGLED = 3

TX_CREATE_SIGNAL = 1
TX_WRITE_SIGNAL = 2
TX_CREATE_WIDGET = 3
TX_SET_PROPERTY = 4
TX_ADD_CHILD = 5
TX_MOUNT = 6
TX_CREATE_COLLECTION = 7
TX_COLLECTION_INSERT = 8
TX_COLLECTION_UPDATE = 9
TX_COLLECTION_REMOVE = 10
TX_CREATE_FOR = 11
TX_CREATE_WHEN = 12
TX_TEMPLATE_END = 13
TX_COLLECTION_UPDATE_FIELD = 14
APPLY_CREATE = 1
APPLY_SET_PROP = 2
APPLY_ADD_CHILD = 3
APPLY_MOUNT = 4
APPLY_DESTROY = 5
OCC_BUTTON_CLICKED = 1
OCC_TEXT_CHANGED = 2
OCC_TOGGLED = 3


def _pad(b):
    return b + b"\0" * (-len(b) % 8)


class _enc:
    """Encoders, namespaced so no generated parameter can shadow them."""

    @staticmethod
    def value(v):
        """Encode a Python scalar as a kaya value."""
        if isinstance(v, bool):
            return _pad(struct.pack("<II", VALUE_BOOL, 1) + bytes([v]))
        if isinstance(v, int):
            return struct.pack("<IIq", VALUE_I64, 8, v)
        if isinstance(v, float):
            return struct.pack("<IId", VALUE_F64, 8, v)
        utf8 = v.encode()
        return _pad(struct.pack("<II", VALUE_STR, len(utf8)) + utf8)


    @staticmethod
    def values(vals):
        """Encode a counted value sequence: a key path or a record."""
        return struct.pack("<II", len(vals), 0) + b"".join(_enc.value(v) for v in vals)


    @staticmethod
    def type_tags(schema):
        """Encode a collection schema: a counted list of VALUE_* tags."""
        return _pad(struct.pack("<II", len(schema), 0) + b"".join(struct.pack("<I", t) for t in schema))


def record(kind, body):
    """Frame one record."""
    body = _pad(body)
    return struct.pack("<IHH", 8 + len(body), kind, 0) + body


def tx_create_signal(signal_id, initial):
    """Create a signal holding `initial`."""
    return record(TX_CREATE_SIGNAL, struct.pack("<Q", signal_id) + _enc.value(initial))

def tx_write_signal(signal_id, value):
    """Replace a signal's value; keep-latest per batch."""
    return record(TX_WRITE_SIGNAL, struct.pack("<Q", signal_id) + _enc.value(value))

def tx_create_widget(widget_id, kind):
    """Create a live widget, or declare a template node inside a scope."""
    return record(TX_CREATE_WIDGET, struct.pack("<Q", widget_id) + struct.pack("<I", kind) + struct.pack("<I", 0))

def tx_add_child(parent, child):
    """Append `child` to `parent` (same zone only)."""
    return record(TX_ADD_CHILD, struct.pack("<Q", parent) + struct.pack("<Q", child))

def tx_mount(window, root):
    """Mount a root into a window (0 = the default window)."""
    return record(TX_MOUNT, struct.pack("<Q", window) + struct.pack("<Q", root))

def tx_create_collection(collection_id, schema):
    """Declare a collection and its schema — the ordered field types every entry must match; a scalar collection is the one-field case. A blueprint when inside a template."""
    return record(TX_CREATE_COLLECTION, struct.pack("<Q", collection_id) + _enc.type_tags(schema))

def tx_collection_insert(collection_id, path, key, fields):
    """Insert an entry into the instance at `path`; the fields match the schema positionally. Stamps a copy."""
    return record(TX_COLLECTION_INSERT, struct.pack("<Q", collection_id) + _enc.values(path) + _enc.value(key) + _enc.values(fields))

def tx_collection_update(collection_id, path, key, fields):
    """Replace an entry's record; every element binding follows."""
    return record(TX_COLLECTION_UPDATE, struct.pack("<Q", collection_id) + _enc.values(path) + _enc.value(key) + _enc.values(fields))

def tx_collection_remove(collection_id, path, key):
    """Remove an entry; its stamped copy tears down."""
    return record(TX_COLLECTION_REMOVE, struct.pack("<Q", collection_id) + _enc.values(path) + _enc.value(key))

def tx_create_for(id, collection_id):
    """A For over a collection; opens a template scope until template_end."""
    return record(TX_CREATE_FOR, struct.pack("<Q", id) + struct.pack("<Q", collection_id))

def tx_create_when(id, signal_id):
    """A When over a Bool signal; opens a template scope until template_end."""
    return record(TX_CREATE_WHEN, struct.pack("<Q", id) + struct.pack("<Q", signal_id))

def tx_template_end():
    """Close the innermost template scope."""
    return record(TX_TEMPLATE_END, b"")

def tx_collection_update_field(collection_id, path, key, field, value):
    """Set one field of an entry's record; only bindings on that field re-resolve."""
    return record(TX_COLLECTION_UPDATE_FIELD, struct.pack("<Q", collection_id) + _enc.values(path) + _enc.value(key) + struct.pack("<I", field) + struct.pack("<I", 0) + _enc.value(value))


def tx_set_text(widget_id, text):
    """set_property with a constant text value (str)."""
    return record(TX_SET_PROPERTY, struct.pack("<QII", widget_id, PROP_TEXT, SOURCE_CONST) + _enc.value(text))


def tx_bind_text(widget_id, signal_id):
    """set_property with a signal-bound text value."""
    return record(TX_SET_PROPERTY, struct.pack("<QIIQ", widget_id, PROP_TEXT, SOURCE_SIGNAL, signal_id))


def tx_bind_text_element(widget_id, level=0, field=0):
    """set_property bound to one field of the element of the enclosing For, `level` Fors up."""
    return record(TX_SET_PROPERTY, struct.pack("<QIIII", widget_id, PROP_TEXT, SOURCE_ELEMENT, level, field))


def tx_set_checked(widget_id, checked):
    """set_property with a constant checked value (bool)."""
    return record(TX_SET_PROPERTY, struct.pack("<QII", widget_id, PROP_CHECKED, SOURCE_CONST) + _enc.value(checked))


def tx_bind_checked(widget_id, signal_id):
    """set_property with a signal-bound checked value."""
    return record(TX_SET_PROPERTY, struct.pack("<QIIQ", widget_id, PROP_CHECKED, SOURCE_SIGNAL, signal_id))


def tx_bind_checked_element(widget_id, level=0, field=0):
    """set_property bound to one field of the element of the enclosing For, `level` Fors up."""
    return record(TX_SET_PROPERTY, struct.pack("<QIIII", widget_id, PROP_CHECKED, SOURCE_ELEMENT, level, field))


def parse_value(buf, at):
    """Decode one value; returns (python value, next offset)."""
    vtype, vlen = struct.unpack_from("<II", buf, at)
    payload = buf[at + 8:at + 8 + vlen]
    end = at + 8 + ((vlen + 7) & ~7)
    if vtype == VALUE_BOOL:
        return payload[0] != 0, end
    if vtype == VALUE_I64:
        return struct.unpack("<q", payload)[0], end
    if vtype == VALUE_F64:
        return struct.unpack("<d", payload)[0], end
    if vtype == VALUE_STR:
        return payload.decode(), end
    raise ValueError(f"unknown value type {vtype}")


def parse_occurrence(buf):
    """Decode one occurrence record (header included).

    Returns (kind, id, keys, payload). keys is [] when id is a
    widget id, else id is a template node id and keys is the
    copy's key path. text is the entry's new content for
    OCC_TEXT_CHANGED, None otherwise.
    """
    _size, kind, _flags = struct.unpack_from("<IHH", buf, 0)
    if kind not in (OCC_BUTTON_CLICKED, OCC_TEXT_CHANGED, OCC_TOGGLED):
        return kind, None, [], None
    ident, path_len = struct.unpack_from("<QI", buf, 8)
    keys = []
    at = 24
    for _ in range(path_len):
        key, at = parse_value(buf, at)
        keys.append(key)
    payload = None
    if kind in (OCC_TEXT_CHANGED, OCC_TOGGLED):
        payload, at = parse_value(buf, at)
    return kind, ident, keys, payload
